async (page) => {
  const rows = await page.$$eval('#release-history table tbody tr', rows => {
    return rows.map(row => {
      const cells = row.querySelectorAll('td');
      if (cells.length >= 2) {
        const version = cells[0].textContent.trim();
        const date = cells[1].textContent.trim();
        return {version, date};
      }
      return null;
    }).filter(Boolean);
  });

  let latestStable = null;
  let oldest = rows[rows.length - 1];
  let total = rows.length;

  for (let i = 0; i < rows.length; i++) {
    const v = rows[i].version;
    if (!v.includes('a') && !v.includes('b') && !v.includes('rc') && !v.includes('dev') && !v.includes('alpha') && !v.includes('beta')) {
      if (!latestStable) latestStable = rows[i];
    }
  }

  const latestDate = latestStable ? latestStable.date : null;
  return {latestStable: latestStable ? latestStable.version : null, oldest: oldest ? oldest.version : null, total, latestDate};
}

